### Stage 3: GenerationEngine (D63)

## Core Types

```rust
pub struct RetrievalOpts {
    pub limit: usize,                          // default 10
    pub expand_graph: bool,                    // follow graph edges, default true
    pub graph_depth: usize,                    // max hops, default 2
    pub visibility: VisibilityMode,
    pub agent_id: Option<String>,
    pub permissions: Option<AgentPermission>,
}

pub struct TokenBudget {
    pub max_context_tokens: Option<usize>,     // None = model-aware auto-sizing
    pub reserve_for_answer: f32,               // fraction reserved for generation, default 0.2
}

pub struct RetrievalResult {
    pub results: Vec<SearchResult>,
    pub metrics: RetrievalMetrics,
}

pub struct AugmentedContext {
    pub system_prompt: String,
    pub context: String,                       // formatted source text
    pub sources: Vec<SearchResult>,            // entries included in context
    pub metrics: AugmentationMetrics,
}

pub struct GenerationResult {
    pub text: String,
    pub model: String,
    pub input_tokens: usize,
    pub output_tokens: usize,
}

pub struct RagResponse {
    pub answer: Option<String>,                // None for context-only mode
    pub context: AugmentedContext,
    pub trace: PipelineTrace,
}
```


## RagPipeline

```rust
pub struct RagPipeline {
    retriever: Arc<dyn Retriever>,
    augmenter: Arc<dyn Augmenter>,
    generator: Option<Arc<dyn GenerationEngine>>,
    config: RagConfig,
}

impl RagPipeline {
    /// Context-only mode: retrieve + augment, no generation.
    pub async fn context(
        &self,
        query: &str,
        scope_id: &str,
        opts: Option<RetrievalOpts>,
    ) -> Result<RagResponse>;

    /// Full RAG: retrieve + augment + generate.
    /// Returns error if GenerationEngine is not configured.
    pub async fn ask(
        &self,
        query: &str,
        scope_id: &str,
        opts: Option<RetrievalOpts>,
    ) -> Result<RagResponse>;
}
```
